<?php
/**
 * AJAX: Issue Library Book
 * 
 * @author School ERP Development Team
 * @version 1.0.0
 */

// Start output buffering FIRST to catch any unwanted output
ob_start();

require_once '../../config/config.php';

// NOW suppress error display AFTER config is loaded
error_reporting(E_ALL);
ini_set('display_errors', 0);
ini_set('display_startup_errors', 0);

// Clear any output that might have been generated by config.php
ob_clean();

// Set JSON header early
header('Content-Type: application/json; charset=utf-8');
header('Cache-Control: no-cache, must-revalidate');

// Support both session-based (web) and user_id parameter (Flutter/mobile) authentication
$currentUser = null;
$userId = $_POST['user_id'] ?? json_decode(file_get_contents('php://input'), true)['user_id'] ?? null;

if ($userId) {
    // Flutter/mobile app authentication
    $sql = "SELECT u.*, r.role_name, b.branch_name 
            FROM users u 
            LEFT JOIN roles r ON u.role_id = r.id 
            LEFT JOIN branches b ON u.branch_id = b.id 
            WHERE u.id = ? AND u.is_active = 1";
    $stmt = executeQuery($sql, 'i', [$userId]);
    $currentUser = fetchOne($stmt);
    
    if (!$currentUser) {
        jsonResponse(false, 'Invalid user ID');
    }
    
    $allowedRoles = ['Super Admin', 'Admin', 'Librarian'];
    if (!in_array($currentUser['role_name'], $allowedRoles)) {
        jsonResponse(false, 'Permission denied');
    }
} else {
    // Web session-based authentication
    if (!isLoggedIn()) jsonResponse(false, 'Unauthorized');
    if (!hasRole(['Super Admin', 'Admin', 'Librarian'])) jsonResponse(false, 'Permission denied');
    $currentUser = getCurrentUser();
}

$input = file_get_contents('php://input');
$data = json_decode($input, true);

if (!$data) {
    $data = $_POST;
}

$bookId = $data['book_id'] ?? 0;
$memberId = $data['member_id'] ?? 0;
$memberType = $data['member_type'] ?? 'Student';
$issueDate = $data['issue_date'] ?? date('Y-m-d');
$dueDate = $data['due_date'] ?? null;
$remarks = sanitize($data['remarks'] ?? '');

if (empty($bookId) || empty($memberId) || empty($dueDate)) {
    jsonResponse(false, 'Book, member, and due date are required');
}

beginTransaction();

try {
    // Check book availability
    $bookSql = "SELECT available_quantity FROM library_books WHERE id = ?";
    $bookStmt = executeQuery($bookSql, 'i', [$bookId]);
    $book = fetchOne($bookStmt);
    
    if (!$book) {
        jsonResponse(false, 'Book not found');
    }
    
    if ($book['available_quantity'] <= 0) {
        jsonResponse(false, 'Book is not available');
    }
    
    // For now, only support Student (library_issues table uses student_id)
    if ($memberType != 'Student') {
        jsonResponse(false, 'Only student book issuance is currently supported');
    }
    
    // Create issue record
    $issueSql = "INSERT INTO library_issues (book_id, student_id, issue_date, due_date, status, remarks, issued_by)
                 VALUES (?, ?, ?, ?, 'Issued', ?, ?)";
    
    $issueStmt = executeQuery($issueSql, 'iisssi', [
        $bookId, $memberId, $issueDate, $dueDate, $remarks, $currentUser['id']
    ]);
    
    if (!$issueStmt) {
        throw new Exception('Failed to create issue record');
    }
    
    // Update book availability
    $updateSql = "UPDATE library_books SET available_quantity = available_quantity - 1 WHERE id = ?";
    executeQuery($updateSql, 'i', [$bookId]);
    
    logActivity($currentUser['id'], 'Issue Book', 'Library', "Issued book ID: $bookId to student ID: $memberId");
    
    commitTransaction();
    jsonResponse(true, 'Book issued successfully!');
    
} catch (Exception $e) {
    rollbackTransaction();
    jsonResponse(false, 'Failed to issue book: ' . $e->getMessage());
}
